// // This module selects between two 8-bit input signals (in1 and in2) based on the value of the selection signal (sel). When sel=0, the output (out) is equal to in1, and when sel=1, the output is equal to in2.
module top_module(input [7:0] in1, input [7:0] in2, input sel, output [7:0] out);assign out = sel ? in1 : in2;
endmodule
